    at::Tensor Bh = B.to(at::kHalf);
    at::Tensor C = at::empty({M, N}, Ah.options().dtype(at::kFloat)); // output float32

    EXEC_NPU_CMD(aclnnMatmulWithTransposedBothCustom, Ah, Bh, C);
    return C;
